class DataImportProcessor {

    ProcessingSummary process(DataImportRequest request) {
        ProcessingSummary summary = new ProcessingSummary();
        summary.setTotalEntities(request.getEntities().size());

        for (EntityRecord entity : request.getEntities()) {
            processEntity(entity, request.getImportMode(), summary, 0);
        }

        if (summary.getRejectedEntities() == 0) {
            summary.setSuccess(true);
        }
        return summary;
    }

    private void processEntity(EntityRecord entity, String importMode, ProcessingSummary summary, int depth) {
        if (entity == null) {
            return;
        }

        boolean valid = validateEntity(entity);
        if (!valid) {
            summary.incrementRejectedEntities();
            summary.addMessage("Rejected entity " + entity.getEntityId() + " at depth " + depth);
            return;
        }

        simulateLargePayloadImport(entity, importMode);
        summary.incrementProcessedEntities();
        summary.addMessage("Processed entity " + entity.getEntityId() + " type=" + entity.getEntityType() + " mode=" + importMode);

        for (EntityRecord child : entity.getChildren()) {
            summary.incrementTotalEntities();
            processEntity(child, importMode, summary, depth + 1);
        }
    }

    private boolean validateEntity(EntityRecord entity) {
        return entity.getEntityId() != null
                && !entity.getEntityId().trim().isEmpty()
                && entity.getEntityType() != null
                && !entity.getEntityType().trim().isEmpty();
    }

    private void simulateLargePayloadImport(EntityRecord entity, String importMode) {
        int checksum = 0;
        for (FieldValue field : entity.getFields()) {
            checksum += field.getName().hashCode();
            checksum += field.getType().hashCode();
            checksum += field.getValue().hashCode();
        }
        checksum += importMode.hashCode();
        if (checksum == Integer.MIN_VALUE) {
            throw new IllegalStateException("Unexpected processing state");
        }
    }
}

